     1вЖТimport type { Metadata } from "next";
     2вЖТimport { Fraunces, DM_Sans } from "next/font/google";
     3вЖТimport { AuthProvider } from "@/lib/auth/context";
     4вЖТimport { LayoutShell } from "@/components/layout/layout-shell";
     5вЖТimport "./globals.css";
     6вЖТ
     7вЖТconst fraunces = Fraunces({
