    20вЖТexport const metadata: Metadata = {
    21вЖТ  title: "Changelogue",
    22вЖТ  description: "Agent-driven release intelligence platform",
    23вЖТ  icons: {
    24вЖТ    icon: "/favicon.svg",
    25вЖТ  },
    26вЖТ};
    27вЖТ
    28вЖТexport default function RootLayout({
    29вЖТ  children,
    30вЖТ}: Readonly<{
    31вЖТ  children: React.ReactNode;
    32вЖТ}>) {
    33вЖТ  return (
