     1вЖТ"use client";
     2вЖТ
     3вЖТimport { useState } from "react";
     4вЖТimport Link from "next/link";
     5вЖТimport { usePathname } from "next/navigation";
     6вЖТimport {
     7вЖТ  LayoutDashboard,
     8вЖТ  ListTodo,
     9вЖТ  FolderKanban,
    10вЖТ  Package,
    11вЖТ  Bell,
    12вЖТ  Megaphone,
    13вЖТ  PanelLeftOpen,
    14вЖТ  PanelLeftClose,
    15вЖТ  LogOut,
    16вЖТ} from "lucide-react";
    17вЖТimport { cn } from "@/lib/utils";
    18вЖТimport { useAuth } from "@/lib/auth/context";
    19вЖТ
    20вЖТconst navItems = [
    21вЖТ  { href: "/", label: "Dashboard", icon: LayoutDashboard },
    22вЖТ  { href: "/projects", label: "Projects", icon: FolderKanban },
    23вЖТ  { href: "/todo", label: "Todo", icon: ListTodo },
    24вЖТ  { href: "/releases", label: "Releases", icon: Package },
    25вЖТ  { href: "/channels", label: "Channels", icon: Megaphone },
    26вЖТ  { href: "/subscriptions", label: "Subscriptions", icon: Bell },
    27вЖТ];
    28вЖТ
    29вЖТexport function Sidebar() {
    30вЖТ  const pathname = usePathname();
    31вЖТ  const [expanded, setExpanded] = useState(false);
    32вЖТ  const { user, logout } = useAuth();
    33вЖТ
    34вЖТ  return (
    35вЖТ    <aside
    36вЖТ      className={cn(
    37вЖТ        "flex shrink-0 flex-col transition-[width] duration-200",
    38вЖТ        expanded ? "w-[200px]" : "w-[52px]"
    39вЖТ      )}
    40вЖТ      style={{ backgroundColor: "#16181c" }}
    41вЖТ    >
    42вЖТ      {/* Logo + toggle */}
    43вЖТ      <div className="flex h-12 items-center px-3">
    44вЖТ        {expanded ? (
    45вЖТ          <>
    46вЖТ            <img src="/logo.svg" alt="" className="h-7 w-7 shrink-0" />
    47вЖТ            <Link
    48вЖТ              href="/"
    49вЖТ              className="ml-2 text-[16px] italic text-white"
    50вЖТ              style={{ fontFamily: "var(--font-fraunces)" }}
    51вЖТ            >
    52вЖТ              Changelogue
    53вЖТ            </Link>
    54вЖТ            <button
    55вЖТ              onClick={() => setExpanded(false)}
    56вЖТ              className="ml-auto text-[#9ca3af] transition-colors hover:text-white"
    57вЖТ              title="Collapse sidebar"
    58вЖТ            >
    59вЖТ              <PanelLeftClose className="h-4 w-4" />
    60вЖТ            </button>
    61вЖТ          </>
    62вЖТ        ) : (
    63вЖТ          <button
    64вЖТ            onClick={() => setExpanded(true)}
    65вЖТ            className="mx-auto text-[#9ca3af] transition-colors hover:text-white"
    66вЖТ            title="Expand sidebar"
    67вЖТ          >
    68вЖТ            <PanelLeftOpen className="h-4 w-4" />
    69вЖТ          </button>
    70вЖТ        )}
    71вЖТ      </div>
    72вЖТ
    73вЖТ      {/* Nav */}
    74вЖТ      <nav className="flex-1 pt-2">
    75вЖТ        {navItems.map((item) => {
    76вЖТ          const isActive =
    77вЖТ            item.href === "/"
    78вЖТ              ? pathname === "/"
    79вЖТ              : pathname.startsWith(item.href);
    80вЖТ          return (
    81вЖТ            <Link
    82вЖТ              key={item.href}
    83вЖТ              href={item.href}
    84вЖТ              title={expanded ? undefined : item.label}
    85вЖТ              className={cn(
    86вЖТ                "flex items-center gap-3 py-2 text-[13px] transition-colors duration-150",
    87вЖТ                expanded ? "pl-4 pr-3" : "justify-center px-0",
    88вЖТ                isActive
    89вЖТ                  ? "text-white"
    90вЖТ                  : "text-[#9ca3af] hover:text-white"
    91вЖТ              )}
    92вЖТ              style={
    93вЖТ                isActive
    94вЖТ                  ? {
    95вЖТ                      borderLeft: "3px solid #e8601a",
    96вЖТ                      backgroundColor: "rgba(255,255,255,0.06)",
    97вЖТ                      paddingLeft: expanded ? "13px" : undefined,
    98вЖТ                    }
    99вЖТ                  : { borderLeft: "3px solid transparent" }
   100вЖТ              }
   101вЖТ            >
   102вЖТ              <item.icon className="h-4 w-4 shrink-0" />
   103вЖТ              {expanded && (
   104вЖТ                <span style={{ fontFamily: "var(--font-dm-sans)" }}>
   105вЖТ                  {item.label}
   106вЖТ                </span>
   107вЖТ              )}
   108вЖТ            </Link>
   109вЖТ          );
   110вЖТ        })}
   111вЖТ      </nav>
   112вЖТ
   113вЖТ      {/* User section */}
   114вЖТ      {user && (
   115вЖТ        <div className="border-t border-[rgba(255,255,255,0.1)] p-2">
   116вЖТ          <div className={cn("flex items-center gap-2", expanded ? "px-2" : "justify-center")}>
   117вЖТ            {user.avatar_url ? (
   118вЖТ              <img
   119вЖТ                src={user.avatar_url}
   120вЖТ                alt={user.github_login}
   121вЖТ                className="h-6 w-6 shrink-0 rounded-full"
   122вЖТ              />
   123вЖТ            ) : (
   124вЖТ              <div className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-[#e8601a] text-xs text-white">
   125вЖТ                {user.github_login[0].toUpperCase()}
   126вЖТ              </div>
   127вЖТ            )}
   128вЖТ            {expanded && (
   129вЖТ              <div className="flex flex-1 items-center justify-between">
   130вЖТ                <span className="truncate text-xs text-[#9ca3af]">{user.github_login}</span>
   131вЖТ                <button
   132вЖТ                  onClick={logout}
   133вЖТ                  title="Sign out"
   134вЖТ                  className="text-[#9ca3af] transition-colors hover:text-white"
   135вЖТ                >
   136вЖТ                  <LogOut className="h-3.5 w-3.5" />
   137вЖТ                </button>
   138вЖТ              </div>
   139вЖТ            )}
   140вЖТ          </div>
   141вЖТ        </div>
   142вЖТ      )}
   143вЖТ    </aside>
   144вЖТ  );
   145вЖТ}
