     1вЖТ"use client";
     2вЖТ
     3вЖТimport {
     4вЖТ  createContext,
     5вЖТ  useContext,
     6вЖТ  useEffect,
     7вЖТ  useRef,
     8вЖТ  useState,
     9вЖТ  type ReactNode,
    10вЖТ} from "react";
    11вЖТimport { usePathname, useRouter } from "next/navigation";
    12вЖТ
    13вЖТinterface User {
    14вЖТ  id: string;
    15вЖТ  github_id: number;
    16вЖТ  github_login: string;
    17вЖТ  name?: string;
    18вЖТ  avatar_url?: string;
    19вЖТ}
    20вЖТ
    21вЖТinterface AuthContextValue {
    22вЖТ  user: User | null;
    23вЖТ  loading: boolean;
    24вЖТ  logout: () => Promise<void>;
    25вЖТ}
    26вЖТ
    27вЖТconst AuthContext = createContext<AuthContextValue>({
    28вЖТ  user: null,
    29вЖТ  loading: true,
    30вЖТ  logout: async () => {},
    31вЖТ});
    32вЖТ
    33вЖТexport function useAuth() {
    34вЖТ  return useContext(AuthContext);
    35вЖТ}
    36вЖТ
    37вЖТexport function AuthProvider({ children }: { children: ReactNode }) {
    38вЖТ  const [user, setUser] = useState<User | null>(null);
    39вЖТ  const [loading, setLoading] = useState(true);
    40вЖТ  const pathname = usePathname();
    41вЖТ  const router = useRouter();
    42вЖТ  const didFetch = useRef(false);
    43вЖТ
    44вЖТ  useEffect(() => {
    45вЖТ    if (didFetch.current) return;
    46вЖТ    didFetch.current = true;
    47вЖТ
    48вЖТ    fetch("/auth/me")
    49вЖТ      .then((res) => {
    50вЖТ        if (res.ok) return res.json();
    51вЖТ        throw new Error("unauthorized");
    52вЖТ      })
    53вЖТ      .then((data) => {
    54вЖТ        setUser(data);
    55вЖТ        setLoading(false);
    56вЖТ      })
    57вЖТ      .catch(() => {
    58вЖТ        setUser(null);
    59вЖТ        setLoading(false);
    60вЖТ      });
    61вЖТ  }, []);
    62вЖТ
    63вЖТ  // Redirect to /login when not authenticated and not already on /login
    64вЖТ  useEffect(() => {
    65вЖТ    if (!loading && !user && pathname !== "/login") {
    66вЖТ      router.replace("/login");
    67вЖТ    }
    68вЖТ  }, [loading, user, pathname, router]);
    69вЖТ
    70вЖТ  const logout = async () => {
    71вЖТ    await fetch("/auth/logout", { method: "POST" });
    72вЖТ    setUser(null);
    73вЖТ    router.replace("/login");
    74вЖТ  };
    75вЖТ
    76вЖТ  if (loading) {
    77вЖТ    return (
    78вЖТ      <div className="flex h-screen items-center justify-center bg-[#f8f8f6]">
    79вЖТ        <div className="h-6 w-6 animate-spin rounded-full border-2 border-[#e8601a] border-t-transparent" />
    80вЖТ      </div>
    81вЖТ    );
    82вЖТ  }
    83вЖТ
    84вЖТ  // On login page, render without redirect guard
    85вЖТ  if (pathname === "/login") {
    86вЖТ    return (
    87вЖТ      <AuthContext.Provider value={{ user, loading, logout }}>
    88вЖТ        {children}
    89вЖТ      </AuthContext.Provider>
    90вЖТ    );
    91вЖТ  }
    92вЖТ
