     4вЖТimport { useEffect } from "react";
     5вЖТimport useSWR, { mutate } from "swr";
     6вЖТimport { StatsCards } from "@/components/dashboard/stats-cards";
     7вЖТimport { ReleaseTrendChart } from "@/components/dashboard/release-trend-chart";
     8вЖТimport { UnifiedFeed } from "@/components/dashboard/unified-feed";
     9вЖТimport { DashboardEmptyState } from "@/components/dashboard/empty-state";
    10вЖТimport { DiscoverySection } from "@/components/dashboard/discovery-section";
    11вЖТimport { SuggestionsSection } from "@/components/dashboard/suggestions-section";
    12вЖТimport { projects as projectsApi } from "@/lib/api/client";
    13вЖТimport { useAuth } from "@/lib/auth/context";
    14вЖТ
    15вЖТconst SSE_BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
    16вЖТ
    17вЖТexport default function DashboardPage() {
    18вЖТ  const { user } = useAuth();
    19вЖТ  const { data: projectsData, isLoading } = useSWR("projects-for-dashboard", () =>
    20вЖТ    projectsApi.list()
    21вЖТ  );
    22вЖТ
    23вЖТ  // Listen to SSE events and revalidate dashboard data on new releases
    24вЖТ  useEffect(() => {
    25вЖТ    let es: EventSource | null = null;
    26вЖТ    let retryTimer: ReturnType<typeof setTimeout> | null = null;
    27вЖТ
    28вЖТ    function connect() {
    29вЖТ      try {
    30вЖТ        es = new EventSource(`${SSE_BASE}/events`);
    31вЖТ        es.onmessage = () => {
    32вЖТ          // Revalidate all dashboard SWR keys on any event
    33вЖТ          mutate((key) => typeof key === "string" && (
    34вЖТ            key === "stats" ||
    35вЖТ            key.startsWith("trend-") ||
    36вЖТ            key === "unified-feed"
    37вЖТ          ), undefined, { revalidate: true });
    38вЖТ        };
    39вЖТ        es.onerror = () => {
    40вЖТ          es?.close();
    41вЖТ          retryTimer = setTimeout(connect, 5000);
    42вЖТ        };
    43вЖТ      } catch {
    44вЖТ        retryTimer = setTimeout(connect, 5000);
    45вЖТ      }
    46вЖТ    }
    47вЖТ
    48вЖТ    connect();
    49вЖТ    return () => {
    50вЖТ      es?.close();
    51вЖТ      if (retryTimer) clearTimeout(retryTimer);
    52вЖТ    };
    53вЖТ  }, []);
    54вЖТ
    55вЖТ  const hasProjects = !isLoading && projectsData?.data && projectsData.data.length > 0;
    56вЖТ
    57вЖТ  return (
    58вЖТ    <div className="space-y-6">
    59вЖТ      <h1
    60вЖТ        style={{
    61вЖТ          fontFamily: "var(--font-fraunces)",
    62вЖТ          fontSize: "24px",
    63вЖТ          fontWeight: 700,
    64вЖТ          color: "#111113",
    65вЖТ        }}
    66вЖТ      >
    67вЖТ        Dashboard
    68вЖТ      </h1>
    69вЖТ
    70вЖТ      {user?.github_login && user.github_login !== "dev" ? (
    71вЖТ        <SuggestionsSection showAuthTabs />
    72вЖТ      ) : (
    73вЖТ        <>
    74вЖТ          <DiscoverySection />
    75вЖТ          <SuggestionsSection />
    76вЖТ        </>
    77вЖТ      )}
    78вЖТ
    79вЖТ      {hasProjects ? (
    80вЖТ        <>
    81вЖТ          <StatsCards />
    82вЖТ          <div className="grid gap-4 lg:grid-cols-2">
    83вЖТ            <ReleaseTrendChart />
    84вЖТ            <UnifiedFeed />
    85вЖТ          </div>
    86вЖТ        </>
    87вЖТ      ) : isLoading ? (
    88вЖТ        <div
    89вЖТ          className="py-16 text-center"
    90вЖТ          style={{
    91вЖТ            fontFamily: "var(--font-dm-sans)",
    92вЖТ            fontSize: "13px",
    93вЖТ            color: "#6b7280",
    94вЖТ          }}
    95вЖТ        >
    96вЖТ          Loading...
    97вЖТ        </div>
    98вЖТ      ) : (
    99вЖТ        <DashboardEmptyState />
   100вЖТ      )}
   101вЖТ    </div>
   102вЖТ  );
   103вЖТ}
