    23вЖТexport function Header() {
    24вЖТ  const pathname = usePathname();
    25вЖТ  const segments = pathname.split("/").filter(Boolean);
    26вЖТ
    27вЖТ  const uuidRe = /^[0-9a-f-]{8,}$/i;
    28вЖТ  const breadcrumbs = segments
    29вЖТ    .filter((s) => !uuidRe.test(s))
    30вЖТ    .map(segmentLabel);
    31вЖТ
    32вЖТ  const display =
    33вЖТ    breadcrumbs.length === 0
    34вЖТ      ? "Dashboard"
    35вЖТ      : breadcrumbs.join(" / ");
    36вЖТ
    37вЖТ  return (
    38вЖТ    <header
    39вЖТ      className="flex h-12 items-center px-6"
    40вЖТ      style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
    41вЖТ    >
    42вЖТ      <p
    43вЖТ        className="text-[14px] font-medium text-[#111113]"
    44вЖТ        style={{ fontFamily: "var(--font-dm-sans)" }}
    45вЖТ      >
    46вЖТ        {display}
    47вЖТ      </p>
    48вЖТ    </header>
    49вЖТ  );
    50вЖТ}
