     1вЖТ"use client";
     2вЖТ
     3вЖТimport {
     4вЖТ  createContext,
     5вЖТ  useContext,
     6вЖТ  useState,
     7вЖТ  useEffect,
     8вЖТ  useCallback,
     9вЖТ  type ReactNode,
    10вЖТ} from "react";
    11вЖТimport en from "./messages/en.json";
    12вЖТimport zh from "./messages/zh.json";
    13вЖТ
    14вЖТconst messages: Record<string, Record<string, string>> = { en, zh };
    15вЖТ
    16вЖТtype Locale = "en" | "zh";
    17вЖТ
    18вЖТinterface I18nContextValue {
    19вЖТ  locale: Locale;
    20вЖТ  setLocale: (locale: Locale) => void;
    21вЖТ  t: (key: string) => string;
    22вЖТ}
    23вЖТ
    24вЖТconst I18nContext = createContext<I18nContextValue | null>(null);
    25вЖТ
    26вЖТconst STORAGE_KEY = "changelogue-locale";
    27вЖТ
    28вЖТexport function LanguageProvider({ children }: { children: ReactNode }) {
    29вЖТ  const [locale, setLocaleState] = useState<Locale>("en");
    30вЖТ
    31вЖТ  // Read from localStorage on mount
    32вЖТ  useEffect(() => {
    33вЖТ    const stored = localStorage.getItem(STORAGE_KEY);
    34вЖТ    if (stored === "en" || stored === "zh") {
    35вЖТ      setLocaleState(stored);
    36вЖТ      document.documentElement.lang = stored;
    37вЖТ    }
    38вЖТ  }, []);
    39вЖТ
    40вЖТ  const setLocale = useCallback((next: Locale) => {
    41вЖТ    setLocaleState(next);
    42вЖТ    localStorage.setItem(STORAGE_KEY, next);
    43вЖТ    document.documentElement.lang = next;
    44вЖТ  }, []);
    45вЖТ
    46вЖТ  const t = useCallback(
    47вЖТ    (key: string): string => {
    48вЖТ      return messages[locale]?.[key] ?? messages.en?.[key] ?? key;
    49вЖТ    },
    50вЖТ    [locale]
    51вЖТ  );
    52вЖТ
    53вЖТ  return (
    54вЖТ    <I18nContext.Provider value={{ locale, setLocale, t }}>
    55вЖТ      {children}
    56вЖТ    </I18nContext.Provider>
    57вЖТ  );
    58вЖТ}
    59вЖТ
    60вЖТexport function useTranslation() {
    61вЖТ  const ctx = useContext(I18nContext);
    62вЖТ  if (!ctx) throw new Error("useTranslation must be used within LanguageProvider");
