     2вЖТ"use client";
     3вЖТ
     4вЖТimport { useEffect, useState, useRef } from "react";
     5вЖТimport { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
     6вЖТimport { Badge } from "@/components/ui/badge";
     7вЖТimport type { SSEEvent } from "@/lib/api/types";
     8вЖТ
     9вЖТconst BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
    10вЖТ
    11вЖТconst eventColors: Record<string, string> = {
    12вЖТ  release: "bg-green-100 text-green-800",
    13вЖТ  semantic_release: "bg-blue-100 text-blue-800",
    14вЖТ};
    15вЖТ
    16вЖТfunction formatEvent(event: SSEEvent): string {
    17вЖТ  switch (event.type) {
    18вЖТ    case "release":
    19вЖТ      return `New release: ${event.data.version}`;
    20вЖТ    case "semantic_release":
    21вЖТ      return `Semantic release: ${event.data.version} (${event.data.status})`;
    22вЖТ    default:
    23вЖТ      return "Unknown event";
    24вЖТ  }
    25вЖТ}
    26вЖТ
    27вЖТexport function ActivityFeed() {
    28вЖТ  const [events, setEvents] = useState<SSEEvent[]>([]);
    29вЖТ  const [connected, setConnected] = useState(false);
    30вЖТ  const retryRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    31вЖТ
    32вЖТ  useEffect(() => {
    33вЖТ    let es: EventSource | null = null;
    34вЖТ
    35вЖТ    function connect() {
    36вЖТ      try {
    37вЖТ        es = new EventSource(`${BASE}/events`);
    38вЖТ
    39вЖТ        es.onopen = () => setConnected(true);
    40вЖТ
    41вЖТ        es.onmessage = (msg) => {
    42вЖТ          try {
    43вЖТ            const event = JSON.parse(msg.data) as SSEEvent;
    44вЖТ            setEvents((prev) => [event, ...prev].slice(0, 20));
    45вЖТ          } catch {
    46вЖТ            // ignore parse errors
    47вЖТ          }
    48вЖТ        };
    49вЖТ
    50вЖТ        es.onerror = () => {
    51вЖТ          setConnected(false);
    52вЖТ          es?.close();
    53вЖТ          // Retry connection after 5 seconds
    54вЖТ          retryRef.current = setTimeout(connect, 5000);
    55вЖТ        };
    56вЖТ      } catch {
    57вЖТ        setConnected(false);
    58вЖТ        retryRef.current = setTimeout(connect, 5000);
    59вЖТ      }
    60вЖТ    }
    61вЖТ
    62вЖТ    connect();
    63вЖТ
    64вЖТ    return () => {
    65вЖТ      es?.close();
    66вЖТ      if (retryRef.current) clearTimeout(retryRef.current);
    67вЖТ    };
    68вЖТ  }, []);
    69вЖТ
    70вЖТ  return (
    71вЖТ    <Card>
    72вЖТ      <CardHeader>
    73вЖТ        <CardTitle className="flex items-center gap-2">
    74вЖТ          Live Activity
    75вЖТ          <span className="relative flex h-2 w-2">
    76вЖТ            {connected ? (
    77вЖТ              <>
    78вЖТ                <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-green-400 opacity-75" />
    79вЖТ                <span className="relative inline-flex h-2 w-2 rounded-full bg-green-500" />
    80вЖТ              </>
    81вЖТ            ) : (
    82вЖТ              <span className="relative inline-flex h-2 w-2 rounded-full bg-gray-400" />
    83вЖТ            )}
    84вЖТ          </span>
    85вЖТ        </CardTitle>
    86вЖТ      </CardHeader>
    87вЖТ      <CardContent>
    88вЖТ        {events.length === 0 ? (
    89вЖТ          <p className="py-4 text-center text-sm text-muted-foreground">
    90вЖТ            Waiting for events...
    91вЖТ          </p>
    92вЖТ        ) : (
    93вЖТ          <div className="space-y-2 max-h-80 overflow-y-auto">
    94вЖТ            {events.map((event) => (
    95вЖТ              <div key={event.id} className="flex items-start gap-2 text-sm">
    96вЖТ                <Badge className={`shrink-0 text-xs ${eventColors[event.type] ?? ""}`}>
    97вЖТ                  {event.type}
    98вЖТ                </Badge>
    99вЖТ                <span className="flex-1 text-muted-foreground">{formatEvent(event)}</span>
   100вЖТ                <span className="shrink-0 text-xs text-muted-foreground">
   101вЖТ                  {new Date(event.timestamp).toLocaleTimeString()}
   102вЖТ                </span>
   103вЖТ              </div>
   104вЖТ            ))}
   105вЖТ          </div>
   106вЖТ        )}
   107вЖТ      </CardContent>
   108вЖТ    </Card>
   109вЖТ  );
   110вЖТ}
